class Solution:
    def perfectPairs(self, nums):
        cnt = 0
        n = len(nums)
        for i in range(n):
            for j in range(i + 1, n):
                a, b = nums[i], nums[j]
                lo = min(abs(a - b), abs(a + b))
                hi = max(abs(a - b), abs(a + b))
                if lo <= min(abs(a), abs(b)) and hi >= max(abs(a), abs(b)):
                    cnt += 1
        return cnt

