class Solution:
    def perfectPairs(self, nums):
        vals = sorted(abs(x) for x in nums)
        cnt = 0
        lo = 0
        for hi in range(len(vals)):
            while vals[hi] > 2 * vals[lo]:
                lo += 1
            cnt += hi - lo
        return cnt

