var perfectPairs = function(nums) {
    const vals = nums.map(x => Math.abs(x)).sort((a, b) => a - b);
    let cnt = 0, lo = 0;
    for (let hi = 0; hi < vals.length; hi++) {
        while (vals[hi] > 2 * vals[lo]) lo++;
        cnt += hi - lo;
    }
    return cnt;
};
